mapper.select:
SELECT id, vin, time, operate, result
FROM vehicle_lifecycle
WHERE vin = #{vin} and time >= #{startTime}
  AND time <= #{endTime}
ORDER BY time ASC

SELECT vl.*
FROM vehicle_lifecycle vl
         INNER JOIN (
    SELECT operate, MAX(time) AS max_time
    FROM vehicle_lifecycle
    WHERE vin = #{vin}
      AND time <= #{time}
    GROUP BY operate
) latest ON vl.operate = latest.operate AND vl.time = latest.max_time
WHERE vl.vin = #{vin}
